
(()=>{const cards=()=>Array.from(document.querySelectorAll('[data-route-card]')); function filter(q){const t=(q||'').toLowerCase(); let n=0; cards().forEach(c=>{const hit=!t||c.textContent.toLowerCase().includes(t); c.style.display=hit?'':'none'; if(hit)n++}); const count=document.querySelector('[data-route-count]'); if(count)count.textContent=String(n)} document.addEventListener('DOMContentLoaded',()=>{document.querySelectorAll('[data-route-search]').forEach(input=>{input.addEventListener('input',e=>filter(e.target.value)); filter(input.value)}); document.querySelectorAll('[data-export-routes]').forEach(btn=>btn.addEventListener('click',()=>{const routes=cards().map(c=>({title:c.dataset.title,href:c.getAttribute('href'),group:c.dataset.group})); const payload={receiptType:'GoalOSNavigationReceipt',version:'v42',generatedAt:new Date().toISOString(),routes:routes.length,posture:'browser-local public-safe route catalog',routes}; const blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='goalos-navigation-receipt-v42.json'; a.click(); setTimeout(()=>URL.revokeObjectURL(a.href),500)}));});})();
